func incomeMonthLabel(m string) string {
	t, err := time.Parse("2006-01", m)
	if err != nil {
		return m
	}
	return t.Format("January 2006")
}

// stringIDs is a helper that converts an int64 to a string for templ
// expressions; kept here so income.templ stays self-contained.
func stringIDs(v int64) string { return strconv.FormatInt(v, 10) }

